import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Часто задаваемые вопросы для игроков","description":"Ответы на часто задаваемые вопросы касательно Fabric, поступающие от игроков и администраторов серверов.","frontmatter":{"title":"Часто задаваемые вопросы для игроков","description":"Ответы на часто задаваемые вопросы касательно Fabric, поступающие от игроков и администраторов серверов.","files":[]},"headers":[],"relativePath":"ru_ru/1.21.4/players/faq.md","filePath":"versions/1.21.4/translated/ru_ru/players/faq.md","lastUpdated":1760721669000}`);var a={name:`ru_ru/1.21.4/players/faq.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Часто задаваемые вопросы для игроков <a class="header-anchor" href="#h1" aria-label="Permalink to “Часто задаваемые вопросы для игроков”">​</a></h1><p>Есть множество вопросов, которые часто задают, поэтому мы составили их список здесь.</p><h2 id="what-minecraft-versions-does-fabric-support" tabindex="-1">Какие версии Minecraft поддерживает Fabric? <a class="header-anchor" href="#what-minecraft-versions-does-fabric-support" aria-label="Permalink to “Какие версии Minecraft поддерживает Fabric?”">​</a></h2><p>Официально Fabric поддерживает все версии Minecraft, начиная со снапшотов <code>18w43b</code> и выше, а также релизные версии <code>1.14</code> и выше.</p><h2 id="where-can-i-download-published-fabric-mods" tabindex="-1">Где я могу скачать опубликованные моды для Fabric? <a class="header-anchor" href="#where-can-i-download-published-fabric-mods" aria-label="Permalink to “Где я могу скачать опубликованные моды для Fabric?”">​</a></h2><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Всегда убеждайтесь в том, что моды загружены из надёжного источника. Ознакомьтесь с руководством по <a href="./finding-mods">поиску надёжных модов</a> для получения дополнительной информации.</p></div><p>Большинство авторов публикуют свои моды на <a href="https://modrinth.com/mods?g=categories:%27fabric%27" target="_blank" rel="noreferrer">Modrinth</a> и CurseForge, однако некоторые могут размещать их на своих личных сайтах или на других платформах, таких как репозитории GitHub.</p><h2 id="where-can-i-find-pre-made-fabric-modpacks" tabindex="-1">Где я могу найти готовые сборки на Fabric? <a class="header-anchor" href="#where-can-i-find-pre-made-fabric-modpacks" aria-label="Permalink to “Где я могу найти готовые сборки на Fabric?”">​</a></h2><p>Вы можете найти готовые сборки модов на основе Fabric на множестве платформ, таких как:</p><ul><li><a href="https://modrinth.com/modpacks?g=categories:%27fabric%27" target="_blank" rel="noreferrer">Modrinth</a></li><li><a href="https://www.curseforge.com/minecraft/search?class=modpacks&amp;gameVersionTypeId=4" target="_blank" rel="noreferrer">CurseForge</a></li><li><a href="https://www.feed-the-beast.com/ftb-app" target="_blank" rel="noreferrer">Feed The Beast</a></li><li><a href="https://www.technicpack.net/modpacks" target="_blank" rel="noreferrer">Technic</a></li></ul>`,10)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};